#include<bits/stdc++.h>
using namespace std;
int n,m,a[100010];
deque<int> q[100010];
int cnt[100010],cnt0[100010],vis[100010],p;
int main()
{
    scanf("%d%d",&n,&m);
    p=m;
    int id=0,l=1;
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        if(vis[a[i]]!=id)
        {
            cnt[a[i]]=0;
            vis[a[i]]=id;
        }
        if(!cnt[a[i]])
        {
            p--;
        }
        cnt[a[i]]++;
        if(id==1)
        {
            cnt0[a[i]]=cnt[a[i]];
        }
        if(p==0)
        {
            p=m;
            id++;
            for(int j=l;j<=i;j++)
            {
                q[id].push_back(a[j]);
            }
            l=i+1;
        }
    }
    for(int i=1;i<=m;i++)
    {
        if(vis[i]!=id)
        {
            cnt[i]=0;
            vis[i]=id;
        }
    }
    if(l<=n)
    {
        id++;
        for(int i=l;i<=n;i++)
        {
            q[id].push_back(a[i]);
        }
    }
    else
    {
        printf("%d",id);
        return 0;
    }
    int k=id;
    if(k==1)
    {
        printf("1");
        return 0;
    }
    while(1)
    {
        if(q[1].empty()||cnt0[q[1].front()]==1)
        {
            break;
        }
        int tmp=q[1].front();
        cnt0[tmp]--;
        if(cnt[tmp]==0)
        {
            p--;
            if(p==0)
            {
                break;
            }
        }
        cnt[tmp]++;
        q[k].push_back(tmp);
    }
    if(p==0)
    {
        printf("%d",k);
    }
    else
    {
        printf("%d",k-1);
    }
    return 0;
}
